    const response = try http_client.fetch(.{ .location = .{ .url = url }, .method = .GET, .extra_headers = &.{}, .keep_alive = false, .redirect_behavior = .unhandled, .response_writer = &response_body.writer });
    try testing.expectEqual(@as(u10, 200), @intFromEnum(response.status));
    try testing.expectEqualStrings("{\"item_id\":\"ec38df32-ceda-4cfa-9b4a-1aeb94ad551a\"}", response_body.written());
}
